cd "$(cat /tmp/wsdir | cut -d= -f2)"; python3 -c "
import json, glob, os, csv
# latest prediction per qid
preds={}
for f in sorted(glob.glob('predictions/*.json')):
    for e in json.load(open(f)):
        preds[e['question_id']]=e['outcomes']
# resolution dates from q_detail
import re
resd={}
for line in open('memory/q_detail.txt'):
    m=re.match(r'### (\d+) \| res=(\S+) \| (.*)', line)
    if m: resd[m.group(1)]=(m.group(2),m.group(3))
today='2026-02-09'
flag=[]
for qid,o in preds.items():
    if qid not in resd: continue
    rd,typ=resd[qid]
    if rd<=today: continue  # already resolved
    top=max(o.values()) if o else 0
    flag.append((top,qid,rd,typ,o))
flag.sort(reverse=True)
print('ACTIVE preds with top>=0.40, sorted desc:')
for top,qid,rd,typ,o in flag:
    if top>=0.40:
        print(f'{qid} res={rd} top={top:.2f} {typ} :: {o}')
"

